const fs = require('fs');

const DATA_DIR = '/polybot-data';

function loadJson(name) {
  try { return JSON.parse(fs.readFileSync(`${DATA_DIR}/${name}`, 'utf8')); }
  catch { return null; }
}

function fmtUsd(v) { return `$${(v||0).toFixed(2)}`; }

const ctrl = loadJson('control.json');
if (!ctrl) return [];

const alerts = [];

// Budget threshold (95%)
const budgetPct = ctrl.daily_spent_usd / ctrl.daily_budget_usd;
if (budgetPct >= 0.95) {
  alerts.push(`🚨 **Budget nearly exhausted**: ${fmtUsd(ctrl.daily_spent_usd)} / ${fmtUsd(ctrl.daily_budget_usd)} (${(budgetPct*100).toFixed(0)}%)`);
}

// Stop loss proximity (within 10%)
if (ctrl.initial_balance_usd) {
  const currentBalance = ctrl.initial_balance_usd - ctrl.daily_spent_usd;
  const stopLossDistance = currentBalance - ctrl.stop_loss_balance_usd;
  const stopLossPct = stopLossDistance / currentBalance;
  if (stopLossPct <= 0.10 && stopLossPct > 0) {
    alerts.push(`⚠️ **Near stop-loss**: Balance ~${fmtUsd(currentBalance)}, stop-loss at ${fmtUsd(ctrl.stop_loss_balance_usd)}`);
  } else if (stopLossPct <= 0) {
    alerts.push(`🛑 **STOP-LOSS HIT**: Balance ~${fmtUsd(currentBalance)} below ${fmtUsd(ctrl.stop_loss_balance_usd)}`);
  }
}

// No traders enabled
if (!ctrl.enabled_traders || ctrl.enabled_traders.length === 0) {
  alerts.push('⏸️ **No traders enabled** — bot is effectively paused.');
}

// Spreadbot check
const spreadCtrl = loadJson('spread_control.json');
if (spreadCtrl) {
  const spreadBudgetPct = (spreadCtrl.daily_spent_usd||0) / (spreadCtrl.daily_budget_usd||1);
  if (spreadBudgetPct >= 0.95) {
    alerts.push(`🚨 **Spreadbot budget exhausted**: ${fmtUsd(spreadCtrl.daily_spent_usd)} / ${fmtUsd(spreadCtrl.daily_budget_usd)}`);
  }
}

if (alerts.length === 0) return [];

const message = '🔔 **Circuit Breaker Alert**\n\n' + alerts.join('\n');
return [{ json: { message, alertCount: alerts.length } }];
